export type ParsedTransferInstruction<
  TProgram extends string = typeof X_MIX_PROGRAM_ADDRESS,
  TAccountMetas extends readonly AccountMeta[] = readonly AccountMeta[],
> = {
  programAddress: Address<TProgram>;
  accounts: {
    relayer: TAccountMetas[0];
    pool: TAccountMetas[1];
    mint: TAccountMetas[2];
    vault: TAccountMetas[3];
    nullifier: TAccountMetas[4];
    recipient: TAccountMetas[5];
    vaultTokenAccount?: TAccountMetas[6] | undefined;
    recipientTokenAccount?: TAccountMetas[7] | undefined;
    feeCollector: TAccountMetas[8];
    feeCollectorTokenAccount?: TAccountMetas[9] | undefined;
    systemProgram: TAccountMetas[10];
    tokenProgram: TAccountMetas[11];
    associatedTokenProgram: TAccountMetas[12];
  };
  data: TransferInstructionData;
};

export function parseTransferInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>
): ParsedTransferInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 13) {
    // TODO: Coded error.
    throw new Error('Not enough accounts');
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  const getNextOptionalAccount = () => {
    const accountMeta = getNextAccount();
    return accountMeta.address === X_MIX_PROGRAM_ADDRESS
      ? undefined
      : accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      relayer: getNextAccount(),
      pool: getNextAccount(),
      mint: getNextAccount(),
      vault: getNextAccount(),
      nullifier: getNextAccount(),
      recipient: getNextAccount(),
      vaultTokenAccount: getNextOptionalAccount(),
      recipientTokenAccount: getNextOptionalAccount(),
      feeCollector: getNextAccount(),
      feeCollectorTokenAccount: getNextOptionalAccount(),
      systemProgram: getNextAccount(),
      tokenProgram: getNextAccount(),
      associatedTokenProgram: getNextAccount(),
    },
    data: getTransferInstructionDataDecoder().decode(instruction.data),
  };
}
